cpp_oop.cheat:
// Classes & RAII
// Define ctor/dtor for resource management
// Rule of 0/3/5: implement copy/move if you manage resources

struct FileHandle {
    FILE *f;
    FileHandle(const char* path){ f = fopen(path,"r"); }
    ~FileHandle(){ if(f) fclose(f); }
    // forbid copying
    FileHandle(const FileHandle&) = delete;
    FileHandle& operator=(const FileHandle&) = delete;
    // allow move
    FileHandle(FileHandle&& o) noexcept : f(o.f){ o.f = nullptr; }
};

