cpp_memory.cheat:
// Smart pointers
// Use unique_ptr for exclusive ownership, shared_ptr for shared ownership
// Avoid raw owning pointers; prefer make_unique/make_shared

#include <memory>

auto up = std::make_unique<int>(42); // unique ownership
std::shared_ptr<int> sp = std::make_shared<int>(42); // shared ownership

// weak_ptr to break cycles
std::weak_ptr<int> wp = sp;

