cpp_concurrency.cheat:
// Threads & sync primitives
// Use std::thread / std::async for tasks
// Protect shared data with mutex or use atomics

#include <thread>
#include <mutex>

std::mutex mu;
int counter = 0;
void worker(){
  std::lock_guard<std::mutex> lk(mu);
  ++counter;
}

std::thread t(worker); t.join();

